    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n *  linux/mm/page_io.c\n *\n *  Copyright (C) 1991, 1992, 1993, 1994  Linus Torvalds\n *\n *  Swap reorganised 29.12.95, \n *  Asynchronous swapping added 30.12.95. Stephen Tweedie\n *  Removed race in async swapping. 14.4.1996. Bruno Haible\n *  Add swap of shared pages through the page cache. 20.2.1998. Stephen Tweedie\n *  Always use brw_page, life becomes simpler. 12 May 1998 Eric Biederman\n */\n\n#include <linux/mm.h>\n#include <linux/kernel_stat.h>\n#include <linux/gfp.h>\n#include <linux/pagemap.h>\n#include <linux/swap.h>\n#include <linux/bio.h>\n#include <linux/swapops.h>\n#include <linux/writeback.h>\n#include <linux/blkdev.h>\n#include <linux/psi.h>\n#include <linux/uio.h>\n#include <linux/sched/task.h>\n#include <linux/delayacct.h>\n#include <linux/zswap.h>\n#include \"swap.h\"\n\nstatic void __end_swap_bio_write(struct bio *bio)\n{\n\tstruct folio *folio = bio_first_folio_all(bio);\n\n\tif (bio->bi_status) {\n\t\t/*\n\t\t * We failed to write the page out to swap-space.\n\t\t * Re-dirty the page in order to avoid it being reclaimed.\n\t\t * Also print a dire warning that things will go BAD (tm)\n\t\t * very quickly.\n\t\t *\n\t\t * Also clear PG_reclaim to avoid folio_rotate_reclaimable()\n\t\t */\n\t\tfolio_mark_dirty(folio);\n\t\tpr_alert_ratelimited(\"Write-error on swap-device (%u:%u:%llu)\\n\",\n\t\t\t\t     MAJOR(bio_dev(bio)), MINOR(bio_dev(bio)),\n\t\t\t\t     (unsigned long long)bio->bi_iter.bi_sector);\n\t\tfolio_clear_reclaim(folio);\n\t}\n\tfolio_end_writeback(folio);\n}\n\nstatic void end_swap_bio_write(struct bio *bio)\n{\n\t__end_swap_bio_write(bio);\n\tbio_put(bio);\n}\n\nstatic void __end_swap_bio_read(struct bio *bio)\n{\n\tstruct folio *folio = bio_first_folio_all(bio);\n\n\tif (bio->bi_status) {\n\t\tpr_alert_ratelimited(\"Read-error on swap-device (%u:%u:%llu)\\n\",\n\t\t\t\t     MAJOR(bio_dev(bio)), MINOR(bio_dev(bio)),\n\t\t\t\t     (unsigned long long)bio->bi_iter.bi_sector);\n\t} else {\n\t\tfolio_mark_uptodate(folio);\n\t}\n\tfolio_unlock(folio);\n}\n\nstatic void end_swap_bio_read(struct bio *bio)\n{\n\t__end_swap_bio_read(bio);\n\tbio_put(bio);\n}\n\nint generic_swapfile_activate(struct swap_info_struct *sis,\n\t\t\t\tstruct file *swap_file,\n\t\t\t\tsector_t *span)\n{\n\tstruct address_space *mapping = swap_file->f_mapping;\n\tstruct inode *inode = mapping->host;\n\tunsigned blocks_per_page;\n\tunsigned long page_no;\n\tunsigned blkbits;\n\tsector_t probe_block;\n\tsector_t last_block;\n\tsector_t lowest_block = -1;\n\tsector_t highest_block = 0;\n\tint nr_extents = 0;\n\tint ret;\n\n\tblkbits = inode->i_blkbits;\n\tblocks_per_page = PAGE_SIZE >> blkbits;\n\n\t/*\n\t * Map all the blocks into the extent tree.  This code doesn't try\n\t * to be very smart.\n\t */\n\tprobe_block = 0;\n\tpage_no = 0;\n\tlast_block = i_size_read(inode) >> blkbits;\n\twhile ((probe_block + blocks_per_page) <= last_block &&\n\t\t\tpage_no < sis->max) {\n\t\tunsigned block_in_page;\n\t\tsector_t first_block;\n\n\t\tcond_resched();\n\n\t\tfirst_block = probe_block;\n\t\tret = bmap(inode, &first_block);\n\t\tif (ret || !first_block)\n\t\t\tgoto bad_bmap;\n\n\t\t/*\n\t\t * It must be PAGE_SIZE aligned on-disk\n\t\t */\n\t\tif (first_block & (blocks_per_page - 1)) {\n\t\t\tprobe_block++;\n\t\t\tgoto reprobe;\n\t\t}\n\n\t\tfor (block_in_page = 1; block_in_page < blocks_per_page;\n\t\t\t\t\tblock_in_page++) {\n\t\t\tsector_t block;\n\n\t\t\tblock = probe_block + block_in_page;\n\t\t\tret = bmap(inode, &block);\n\t\t\tif (ret || !block)\n\t\t\t\tgoto bad_bmap;\n\n\t\t\tif (block != first_block + block_in_page) {\n\t\t\t\t/* Discontiguity */\n\t\t\t\tprobe_block++;\n\t\t\t\tgoto reprobe;\n\t\t\t}\n\t\t}\n\n\t\tfirst_block >>= (PAGE_SHIFT - blkbits);\n\t\tif (page_no) {\t/* exclude the header page */\n\t\t\tif (first_block < lowest_block)\n\t\t\t\tlowest_block = first_block;\n\t\t\tif (first_block > highest_block)\n\t\t\t\thighest_block = first_block;\n\t\t}\n\n\t\t/*\n\t\t * We found a PAGE_SIZE-length, PAGE_SIZE-aligned run of blocks\n\t\t */\n\t\tret = add_swap_extent(sis, page_no, 1, first_block);\n\t\tif (ret < 0)\n\t\t\tgoto out;\n\t\tnr_extents += ret;\n\t\tpage_no++;\n\t\tprobe_block += blocks_per_page;\nreprobe:\n\t\tcontinue;\n\t}\n\tret = nr_extents;\n\t*span = 1 + highest_block - lowest_block;\n\tif (page_no == 0)\n\t\tpage_no = 1;\t/* force Empty message */\n\tsis->max = page_no;\n\tsis->pages = page_no - 1;\nout:\n\treturn ret;\nbad_bmap:\n\tpr_err(\"swapon: swapfile has holes\\n\");\n\tret = -EINVAL;\n\tgoto out;\n}\n\nstatic bool is_folio_zero_filled(struct folio *folio)\n{\n\tunsigned int pos, last_pos;\n\tunsigned long *data;\n\tunsigned int i;\n\n\tlast_pos = PAGE_SIZE / sizeof(*data) - 1;\n\tfor (i = 0; i < folio_nr_pages(folio); i++) {\n\t\tdata = kmap_local_folio(folio, i * PAGE_SIZE);\n\t\t/*\n\t\t * Check last word first, incase the page is zero-filled at\n\t\t * the start and has non-zero data at the end, which is common\n\t\t * in real-world workloads.\n\t\t */\n\t\tif (data[last_pos]) {\n\t\t\tkunmap_local(data);\n\t\t\treturn false;\n\t\t}\n\t\tfor (pos = 0; pos < last_pos; pos++) {\n\t\t\tif (data[pos]) {\n\t\t\t\tkunmap_local(data);\n\t\t\t\treturn false;\n\t\t\t}\n\t\t}\n\t\tkunmap_local(data);\n\t}\n\n\treturn true;\n}\n\nstatic void swap_zeromap_folio_set(struct folio *folio)\n{\n\tstruct obj_cgroup *objcg = get_obj_cgroup_from_folio(folio);\n\tstruct swap_info_struct *sis = __swap_entry_to_info(folio->swap);\n\tint nr_pages = folio_nr_pages(folio);\n\tswp_entry_t entry;\n\tunsigned int i;\n\n\tfor (i = 0; i < folio_nr_pages(folio); i++) {\n\t\tentry = page_swap_entry(folio_page(folio, i));\n\t\tset_bit(swp_offset(entry), sis->zeromap);\n\t}\n\n\tcount_vm_events(SWPOUT_ZERO, nr_pages);\n\tif (objcg) {\n\t\tcount_objcg_events(objcg, SWPOUT_ZERO, nr_pages);\n\t\tobj_cgroup_put(objcg);\n\t}\n}\n\nstatic void swap_zeromap_folio_clear(struct folio *folio)\n{\n\tstruct swap_info_struct *sis = __swap_entry_to_info(folio->swap);\n\tswp_entry_t entry;\n\tunsigned int i;\n\n\tfor (i = 0; i < folio_nr_pages(folio); i++) {\n\t\tentry = page_swap_entry(folio_page(folio, i));\n\t\tclear_bit(swp_offset(entry), sis->zeromap);\n\t}\n}\n\n/*\n * We may have stale swap cache pages in memory: notice\n * them here and get rid of the unnecessary final write.\n */\nint swap_writeout(struct folio *folio, struct swap_iocb **swap_plug)\n{\n\tint ret = 0;\n\n\tif (folio_free_swap(folio))\n\t\tgoto out_unlock;\n\n\t/*\n\t * Arch code may have to preserve more data than just the page\n\t * contents, e.g. memory tags.\n\t */\n\tret = arch_prepare_to_swap(folio);\n\tif (ret) {\n\t\tfolio_mark_dirty(folio);\n\t\tgoto out_unlock;\n\t}\n\n\t/*\n\t * Use a bitmap (zeromap) to avoid doing IO for zero-filled pages.\n\t * The bits in zeromap are protected by the locked swapcache folio\n\t * and atomic updates are used to protect against read-modify-write\n\t * corruption due to other zero swap entries seeing concurrent updates.\n\t */\n\tif (is_folio_zero_filled(folio)) {\n\t\tswap_zeromap_folio_set(folio);\n\t\tgoto out_unlock;\n\t}\n\n\t/*\n\t * Clear bits this folio occupies in the zeromap to prevent zero data\n\t * being read in from any previous zero writes that occupied the same\n\t * swap entries.\n\t */\n\tswap_zeromap_folio_clear(folio);\n\n\tif (zswap_store(folio)) {\n\t\tcount_mthp_stat(folio_order(folio), MTHP_STAT_ZSWPOUT);\n\t\tgoto out_unlock;\n\t}\n\n\trcu_read_lock();\n\tif (!mem_cgroup_zswap_writeback_enabled(folio_memcg(folio))) {\n\t\trcu_read_unlock();\n\t\tfolio_mark_dirty(folio);\n\t\treturn AOP_WRITEPAGE_ACTIVATE;\n\t}\n\trcu_read_unlock();\n\n\t__swap_writepage(folio, swap_plug);\n\treturn 0;\nout_unlock:\n\tfolio_unlock(folio);\n\treturn ret;\n}\n\nstatic inline void count_swpout_vm_event(struct folio *folio)\n{\n#ifdef CONFIG_TRANSPARENT_HUGEPAGE\n\tif (unlikely(folio_test_pmd_mappable(folio))) {\n\t\tcount_memcg_folio_events(folio, THP_SWPOUT, 1);\n\t\tcount_vm_event(THP_SWPOUT);\n\t}\n#endif\n\tcount_mthp_stat(folio_order(folio), MTHP_STAT_SWPOUT);\n\tcount_memcg_folio_events(folio, PSWPOUT, folio_nr_pages(folio));\n\tcount_vm_events(PSWPOUT, folio_nr_pages(folio));\n}\n\n#if defined(CONFIG_MEMCG) && defined(CONFIG_BLK_CGROUP)\nstatic void bio_associate_blkg_from_page(struct bio *bio, struct folio *folio)\n{\n\tstruct cgroup_subsys_state *css;\n\tstruct mem_cgroup *memcg;\n\n\tif (!folio_memcg_charged(folio))\n\t\treturn;\n\n\trcu_read_lock();\n\tmemcg = folio_memcg(folio);\n\tcss = cgroup_e_css(memcg->css.cgroup, &io_cgrp_subsys);\n\tbio_associate_blkg_from_css(bio, css);\n\trcu_read_unlock();\n}\n#else\n#define bio_associate_blkg_from_page(bio, folio)\t\tdo { } while (0)\n#endif /* CONFIG_MEMCG && CONFIG_BLK_CGROUP */\n\nstruct swap_iocb {\n\tstruct kiocb\t\tiocb;\n\tstruct bio_vec\t\tbvec[SWAP_CLUSTER_MAX];\n\tint\t\t\tpages;\n\tint\t\t\tlen;\n};\nstatic mempool_t *sio_pool;\n\nint sio_pool_init(void)\n{\n\tif (!sio_pool) {\n\t\tmempool_t *pool = mempool_create_kmalloc_pool(\n\t\t\tSWAP_CLUSTER_MAX, sizeof(struct swap_iocb));\n\t\tif (cmpxchg(&sio_pool, NULL, pool))\n\t\t\tmempool_destroy(pool);\n\t}\n\tif (!sio_pool)\n\t\treturn -ENOMEM;\n\treturn 0;\n}\n\nstatic void sio_write_complete(struct kiocb *iocb, long ret)\n{\n\tstruct swap_iocb *sio = container_of(iocb, struct swap_iocb, iocb);\n\tint p;\n\n\tif (ret != sio->len) {\n\t\t/*\n\t\t * In the case of swap-over-nfs, this can be a\n\t\t * temporary failure if the system has limited\n\t\t * memory for allocating transmit buffers.\n\t\t * Mark the folio dirty and avoid\n\t\t * folio_rotate_reclaimable but rate-limit the\n\t\t * messages.\n\t\t */\n\t\tstruct folio *folio = page_folio(sio->bvec[0].bv_page);\n\t\tpr_err_ratelimited(\"Write error %ld on dio swapfile (%llu)\\n\",\n\t\t\t\t   ret, swap_dev_pos(folio->swap));\n\t\tfor (p = 0; p < sio->pages; p++) {\n\t\t\tfolio = page_folio(sio->bvec[p].bv_page);\n\t\t\tfolio_mark_dirty(folio);\n\t\t\tfolio_clear_reclaim(folio);\n\t\t}\n\t}\n\n\tfor (p = 0; p < sio->pages; p++) {\n\t\tstruct folio *folio = page_folio(sio->bvec[p].bv_page);\n\t\tfolio_end_writeback(folio);\n\t}\n\n\tmempool_free(sio, sio_pool);\n}\n\nstatic void swap_writepage_fs(struct folio *folio, struct swap_iocb **swap_plug)\n{\n\tstruct swap_iocb *sio = swap_plug ? *swap_plug : NULL;\n\tstruct swap_info_struct *sis = __swap_entry_to_info(folio->swap);\n\tstruct file *swap_file = sis->swap_file;\n\tloff_t pos = swap_dev_pos(folio->swap);\n\n\tcount_swpout_vm_event(folio);\n\tfolio_start_writeback(folio);\n\tfolio_unlock(folio);\n\tif (sio) {\n\t\tif (sio->iocb.ki_filp != swap_file ||\n\t\t    sio->iocb.ki_pos + sio->len != pos) {\n\t\t\tswap_write_unplug(sio);\n\t\t\tsio = NULL;\n\t\t}\n\t}\n\tif (!sio) {\n\t\tsio = mempool_alloc(sio_pool, GFP_NOIO);\n\t\tinit_sync_kiocb(&sio->iocb, swap_file);\n\t\tsio->iocb.ki_complete = sio_write_complete;\n\t\tsio->iocb.ki_pos = pos;\n\t\tsio->pages = 0;\n\t\tsio->len = 0;\n\t}\n\tbvec_set_folio(&sio->bvec[sio->pages], folio, folio_size(folio), 0);\n\tsio->len += folio_size(folio);\n\tsio->pages += 1;\n\tif (sio->pages == ARRAY_SIZE(sio->bvec) || !swap_plug) {\n\t\tswap_write_unplug(sio);\n\t\tsio = NULL;\n\t}\n\tif (swap_plug)\n\t\t*swap_plug = sio;\n}\n\nstatic void swap_writepage_bdev_sync(struct folio *folio,\n\t\tstruct swap_info_struct *sis)\n{\n\tstruct bio_vec bv;\n\tstruct bio bio;\n\n\tbio_init(&bio, sis->bdev, &bv, 1, REQ_OP_WRITE | REQ_SWAP);\n\tbio.bi_iter.bi_sector = swap_folio_sector(folio);\n\tbio_add_folio_nofail(&bio, folio, folio_size(folio), 0);\n\n\tbio_associate_blkg_from_page(&bio, folio);\n\tcount_swpout_vm_event(folio);\n\n\tfolio_start_writeback(folio);\n\tfolio_unlock(folio);\n\n\tsubmit_bio_wait(&bio);\n\t__end_swap_bio_write(&bio);\n}\n\nstatic void swap_writepage_bdev_async(struct folio *folio,\n\t\tstruct swap_info_struct *sis)\n{\n\tstruct bio *bio;\n\n\tbio = bio_alloc(sis->bdev, 1, REQ_OP_WRITE | REQ_SWAP, GFP_NOIO);\n\tbio->bi_iter.bi_sector = swap_folio_sector(folio);\n\tbio->bi_end_io = end_swap_bio_write;\n\tbio_add_folio_nofail(bio, folio, folio_size(folio), 0);\n\n\tbio_associate_blkg_from_page(bio, folio);\n\tcount_swpout_vm_event(folio);\n\tfolio_start_writeback(folio);\n\tfolio_unlock(folio);\n\tsubmit_bio(bio);\n}\n\nvoid __swap_writepage(struct folio *folio, struct swap_iocb **swap_plug)\n{\n\tstruct swap_info_struct *sis = __swap_entry_to_info(folio->swap);\n\n\tVM_BUG_ON_FOLIO(!folio_test_swapcache(folio), folio);\n\t/*\n\t * ->flags can be updated non-atomically,\n\t * but that will never affect SWP_FS_OPS, so the data_race\n\t * is safe.\n\t */\n\tif (data_race(sis->flags & SWP_FS_OPS))\n\t\tswap_writepage_fs(folio, swap_plug);\n\t/*\n\t * ->flags can be updated non-atomically,\n\t * but that will never affect SWP_SYNCHRONOUS_IO, so the data_race\n\t * is safe.\n\t */\n\telse if (data_race(sis->flags & SWP_SYNCHRONOUS_IO))\n\t\tswap_writepage_bdev_sync(folio, sis);\n\telse\n\t\tswap_writepage_bdev_async(folio, sis);\n}\n\nvoid swap_write_unplug(struct swap_iocb *sio)\n{\n\tstruct iov_iter from;\n\tstruct address_space *mapping = sio->iocb.ki_filp->f_mapping;\n\tint ret;\n\n\tiov_iter_bvec(&from, ITER_SOURCE, sio->bvec, sio->pages, sio->len);\n\tret = mapping->a_ops->swap_rw(&sio->iocb, &from);\n\tif (ret != -EIOCBQUEUED)\n\t\tsio_write_complete(&sio->iocb, ret);\n}\n\nstatic void sio_read_complete(struct kiocb *iocb, long ret)\n{\n\tstruct swap_iocb *sio = container_of(iocb, struct swap_iocb, iocb);\n\tint p;\n\n\tif (ret == sio->len) {\n\t\tfor (p = 0; p < sio->pages; p++) {\n\t\t\tstruct folio *folio = page_folio(sio->bvec[p].bv_page);\n\n\t\t\tcount_mthp_stat(folio_order(folio), MTHP_STAT_SWPIN);\n\t\t\tcount_memcg_folio_events(folio, PSWPIN, folio_nr_pages(folio));\n\t\t\tfolio_mark_uptodate(folio);\n\t\t\tfolio_unlock(folio);\n\t\t}\n\t\tcount_vm_events(PSWPIN, sio->pages);\n\t} else {\n\t\tfor (p = 0; p < sio->pages; p++) {\n\t\t\tstruct folio *folio = page_folio(sio->bvec[p].bv_page);\n\n\t\t\tfolio_unlock(folio);\n\t\t}\n\t\tpr_alert_ratelimited(\"Read-error on swap-device\\n\");\n\t}\n\tmempool_free(sio, sio_pool);\n}\n\nstatic bool swap_read_folio_zeromap(struct folio *folio)\n{\n\tint nr_pages = folio_nr_pages(folio);\n\tstruct obj_cgroup *objcg;\n\tbool is_zeromap;\n\n\t/*\n\t * Swapping in a large folio that is partially in the zeromap is not\n\t * currently handled. Return true without marking the folio uptodate so\n\t * that an IO error is emitted (e.g. do_swap_page() will sigbus).\n\t */\n\tif (WARN_ON_ONCE(swap_zeromap_batch(folio->swap, nr_pages,\n\t\t\t&is_zeromap) != nr_pages))\n\t\treturn true;\n\n\tif (!is_zeromap)\n\t\treturn false;\n\n\tobjcg = get_obj_cgroup_from_folio(folio);\n\tcount_vm_events(SWPIN_ZERO, nr_pages);\n\tif (objcg) {\n\t\tcount_objcg_events(objcg, SWPIN_ZERO, nr_pages);\n\t\tobj_cgroup_put(objcg);\n\t}\n\n\tfolio_zero_range(folio, 0, folio_size(folio));\n\tfolio_mark_uptodate(folio);\n\treturn true;\n}\n\nstatic void swap_read_folio_fs(struct folio *folio, struct swap_iocb **plug)\n{\n\tstruct swap_info_struct *sis = __swap_entry_to_info(folio->swap);\n\tstruct swap_iocb *sio = NULL;\n\tloff_t pos = swap_dev_pos(folio->swap);\n\n\tif (plug)\n\t\tsio = *plug;\n\tif (sio) {\n\t\tif (sio->iocb.ki_filp != sis->swap_file ||\n\t\t    sio->iocb.ki_pos + sio->len != pos) {\n\t\t\tswap_read_unplug(sio);\n\t\t\tsio = NULL;\n\t\t}\n\t}\n\tif (!sio) {\n\t\tsio = mempool_alloc(sio_pool, GFP_KERNEL);\n\t\tinit_sync_kiocb(&sio->iocb, sis->swap_file);\n\t\tsio->iocb.ki_pos = pos;\n\t\tsio->iocb.ki_complete = sio_read_complete;\n\t\tsio->pages = 0;\n\t\tsio->len = 0;\n\t}\n\tbvec_set_folio(&sio->bvec[sio->pages], folio, folio_size(folio), 0);\n\tsio->len += folio_size(folio);\n\tsio->pages += 1;\n\tif (sio->pages == ARRAY_SIZE(sio->bvec) || !plug) {\n\t\tswap_read_unplug(sio);\n\t\tsio = NULL;\n\t}\n\tif (plug)\n\t\t*plug = sio;\n}\n\nstatic void swap_read_folio_bdev_sync(struct folio *folio,\n\t\tstruct swap_